module counter (  
    input obf_clk,  
    input reset,  
    input enable,  
    output reg [3:0] count  
);  
    always @(posedge obf_clk or posedge reset) begin  
        if (reset)  
            count <= 4'b0000;  
        else if (enable)  
            count <= count + 1;  
    end  
endmodule
